import re

from llama_stack_client import LlamaStackAgent

SECRETS_REGEX = {
    'api_keys': r'(?i)(api[-_]?key|secret|token)[\s:=]+[a-zA-Z0-9]{20,}',
    'aws_keys': r'(?i)(aws_access_key_id|aws_secret_access_key)[\s:=]+[A-Z0-9]{20,}',
    'pii_email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
    'pii_ssn': r'\b\d{3}-?\d{2}-?\d{4}\b',
    'credit_card': r'\b(?:\d{4}[\s-]?){3}\d{4}\b'
}

def detect_secrets_in_llamastack_response(response: dict) -> list:
    findings = []
    content = response.get('content', '') + response.get('tool_calls', '')

    for secret_type, pattern in SECRETS_REGEX.items():
        matches = re.finditer(pattern, content)
        for match in matches:
            findings.append({
                'type': secret_type,
                'value': match.group(0),
                'location': f'char {match.start()}-{match.end()}',
                'confidence': 0.95
            })
    return findings

