from llama_stack_client import LlamaStackAgent
import re

def sanitize_tool_params(tool_call: dict) -> dict:
    params = tool_call['parameters']

    # Remove PII from all string parameters
    def scrub_pii(value):
        if isinstance(value, str):
            # Remove emails, SSNs, etc.
            value = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL_REDACTED]', value)
            value = re.sub(r'\b\d{3}-?\d{2}-?\d{4}\b', '[SSN_REDACTED]', value)
        return value

    sanitized_params = {k: scrub_pii(v) for k, v in params.items()}
    return {'parameters': sanitized_params, 'cleaned': True}

from llama_stack_client import LlamaSafetyShield

class DoubleFilterPipeline:
    def __init__(self):
        self.shield = LlamaSafetyShield()

    def filter_response(self, response: dict) -> tuple[bool, str]:
        content = response['content']

        # First pass: Llama Safety Shield
        shield_result = self.shield.classify(content)
        if shield_result['risk'] > 0.3:
            return False, 'blocked_by_shield'

        # Second pass: Custom secrets detection
        secrets = self._detect_secrets(content)
        if secrets:
            return False, f'secrets_detected: {secrets}'

        return True, 'approved'

    def _detect_secrets(self, text: str) -> list:
        patterns = [r'(?i)(api[_-]?key|secret)[\s:=]+[A-Za-z0-9]{20,}']
        return [m.group() for pattern in patterns for m in re.finditer(pattern, text)]

from llama_stack_client import LlamaMemoryBank

class ControlledMemoryBank(LlamaMemoryBank):
    def __init__(self, allowed_domains: list = None):
        super().__init__()
        self.allowed_domains = allowed_domains or []

    def retrieve_relevant(self, query: str, agent_context: dict) -> list:
        docs = super().retrieve_relevant(query, limit=5)

        filtered_docs = []
        for doc in docs:
            if self._is_safe_for_context(doc, agent_context):
                filtered_docs.append(doc)
            else:
                print(f'Blocked sensitive doc: {doc["id"]}')

        return filtered_docs

    def _is_safe_for_context(self, doc: dict, context: dict) -> bool:
        content = doc['content'].lower()
        # Block docs with sensitive indicators
        if any(sensitive in content for sensitive in ['ssn', 'credit card', 'api key', 'password']):
            return False
        return True
